   262→// --- Delete User Cloud Function (Callable) ---
   263→exports.deleteUser = onCall(async (request) => {
   264→  if (!request.auth) {
   265→    throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
   266→  }
   267→
   268→  const callerDoc = await db.collection('users').doc(request.auth.uid).get();
   269→  if (!callerDoc.exists || callerDoc.data().role !== 'admin') {
   270→    throw new HttpsError('permission-denied', 'Only admin users can delete other users.');
   271→  }
   272→
   273→  const uid = request.data.uid;
   274→  if (!uid) {
   275→    throw new HttpsError('invalid-argument', 'The function must be called with a "uid" argument.');
   276→  }
   277→
   278→  try {
   279→    await admin.auth().deleteUser(uid);
   280→    await db.collection('users').doc(uid).delete();
   281→    return { message: `Successfully deleted user ${uid}.` };
   282→  } catch (error) {
   283→    console.error("Error deleting user:", error);
   284→    throw new HttpsError('internal', 'An error occurred while deleting the user.');
   285→  }
   286→});
