   288→// --- Update User Password Cloud Function (Callable) ---
   289→exports.updateUserPassword = onCall(async (request) => {
   290→  if (!request.auth) {
   291→    throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
   292→  }
   293→
   294→  const callerDoc = await db.collection('users').doc(request.auth.uid).get();
   295→  if (!callerDoc.exists || callerDoc.data().role !== 'admin') {
   296→    throw new HttpsError('permission-denied', 'Only admin users can change passwords.');
   297→  }
   298→
   299→  const { uid, newPassword } = request.data;
   300→  if (!uid || !newPassword) {
   301→    throw new HttpsError('invalid-argument', 'The function must be called with "uid" and "newPassword" arguments.');
   302→  }
   303→
   304→  try {
   305→    await admin.auth().updateUser(uid, { password: newPassword });
   306→    return { message: `Password for user ${uid} updated successfully.` };
   307→  } catch (error) {
   308→    console.error("Error updating password:", error);
   309→    throw new HttpsError('internal', 'An error occurred while updating the password.');
   310→  }
   311→});

