    10→export default function ProductForm() {
    11→  const [productName, setProductName] = useState('');
    12→  const [weight, setWeight] = useState('');
    13→  const [unit, setUnit] = useState('g');
    14→  const [expiryDate, setExpiryDate] = useState('');
    15→  const [quantity, setQuantity] = useState(1);
    16→  const [category, setCategory] = useState('');
    17→  const [price, setPrice] = useState('');
    18→  const [photo, setPhoto] = useState(null);
    19→  const [capturedExpiryImage, setCapturedExpiryImage] = useState(null); // New state for captured image data
    20→
    21→  const [isSaving, setIsSaving] = useState(false);
    22→  const [feedback, setFeedback] = useState('');
    23→  const [isScanning, setIsScanning] = useState(false);
    24→  const [ocrFeedback, setOcrFeedback] = useState('');
    25→
    26→  // No longer need to initialize functions via getFunctions(app) here
    27→  const storage = getStorage(app);
    28→
    29→  const handleSaveProduct = async (e) => {
    30→    e.preventDefault();
    31→    setIsSaving(true);
    32→    setFeedback('Sauvegarde...');
    33→
    34→    if (!productName || !weight || !expiryDate || !quantity) {
    35→      setFeedback('Veuillez remplir tous les champs obligatoires (Nom, Poids, Date de péremption, Quantité).');
    36→      setIsSaving(false);
    37→      return;
    38→    }
    39→
    40→    try {
    41→      let photoURLs = [];
    42→      if (photo) {
    43→        const storageRef = ref(storage, `product_photos/${Date.now()}_${photo.name}`);
    44→        const uploadResult = await uploadBytes(storageRef, photo);
    45→        const downloadURL = await getDownloadURL(uploadResult.ref);
    46→        photoURLs.push(downloadURL);
    47→      }
    48→
    49→      await addDoc(collection(db, 'products'), {
    50→        name: productName,
    51→        weight: parseFloat(weight),
    52→        unit: unit,
    53→        expiryDate: Timestamp.fromDate(new Date(expiryDate)),
    54→        quantity: parseInt(quantity),
    55→        category: category || null,
    56→        price: price ? parseFloat(price) : null,
    57→        photos: photoURLs,
    58→        decisionStatus: 'to_handle', // Default status
    59→        creationDate: Timestamp.now(),
    60→      });
    61→      setFeedback('Produit ajouté avec succès !');
    62→      // Clear form
    63→      setProductName('');
    64→      setWeight('');
    65→      setExpiryDate('');
    66→      setQuantity(1);
    67→      setCategory('');
    68→      setPrice('');
    69→      setPhoto(null);
    70→      setCapturedExpiryImage(null); // Clear captured image
    71→    } catch (error) {
    72→      console.error("Error adding product:", error);
    73→      setFeedback('Erreur lors de l\'ajout du produit.');
    74→    } finally {
    75→      setIsSaving(false);
    76→      setTimeout(() => setFeedback(''), 3000);
    77→    }
    78→  };
    79→
    80→  const handleScanProduct = async (imageData) => { // Accept imageData directly
    81→    if (!imageData && !capturedExpiryImage) { // Check both if imageData is passed or if it's already in state
    82→      setOcrFeedback('Veuillez capturer une photo de la date de péremption.');
    83→      setTimeout(() => setOcrFeedback(''), 3000);
    84→      return;
    85→    }
    86→
    87→    setIsScanning(true);
    88→    setOcrFeedback('Scan en cours...');
    89→
    90→    try {
    91→      const base64Image = (imageData || capturedExpiryImage).split(',')[1]; // Use imageData if provided, else from state
    92→      const expectedFunctionUrl = `https://us-central1-dashboard-mictlan-dev.cloudfunctions.net/extractExpiryDateFromImage`;
    93→
    94→      const requestBody = {
    95→          data: base64Image
    96→      };
    97→
    98→      const response = await fetch(expectedFunctionUrl, {
    99→        method: 'POST',
   100→        headers: {
   101→          'Content-Type': 'application/json',
   102→        },
   103→        body: JSON.stringify(requestBody),
   104→      });
   105→
   106→      if (!response.ok) {
   107→        const errorText = await response.text();
   108→        throw new Error(`HTTP error! status: ${response.status}, body: ${errorText}`);
   109→      }
   110→
   111→      const responseData = await response.json();
   112→      const result = responseData.result || responseData; // Handle SDK-like wrapper and direct response
   113→
   114→      if (result && result.expiryDate) {
   115→        setExpiryDate(result.expiryDate);
   116→        setOcrFeedback('Date détectée avec succès !');
   117→      } else if (result && result.message) {
   118→        setOcrFeedback(result.message);
   119→      } else if (responseData.error) {
   120→        setOcrFeedback(`Erreur: ${responseData.error.message}`);
   121→      } else {
   122→        setOcrFeedback(`Erreur inattendue: ${JSON.stringify(responseData)}`);
   123→      }
   124→
   125→    } catch (error) {
   126→      console.error("Error during OCR scan:", error);
   127→      setOcrFeedback(`Erreur lors du scan: ${error.message}`);
   128→    } finally {
   129→      setIsScanning(false);
   130→      setTimeout(() => setOcrFeedback(''), 3000);
   131→    }
   132→  };
   133→
   134→  return (
   135→    <Card title="Ajouter un Produit" titleIcon={<PackagePlus />}>
