   140→            type="text"
   141→            id="productName"
   142→            value={productName}
   143→            onChange={(e) => setProductName(e.target.value)}
   144→            className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
   145→            placeholder="Ex: Yaourt Grec Nature"
   146→            required
   147→          />
   148→        </div>
   149→
   150→        <div className="flex space-x-4">
   151→          <div className="flex-1">
   152→            <label htmlFor="weight" className="block text-gray-400 mb-1">Poids <span className="text-red-500">*</span></label>
   153→            <input
   154→              type="number"
   155→              id="weight"
   156→              value={weight}
   157→              onChange={(e) => setWeight(e.target.value)}
