          { name: 'TheFork', reservations: 10, remaining: 5, capacity: 15 },
          { name: 'Zenchef', reservations: 8, remaining: 7, capacity: 15 },
        ],
      },
      {
        name: 'Soir',
        providers: [
          { name: 'TheFork', reservations: 20, remaining: 10, capacity: 30 },
          { name: 'Zenchef', reservations: 15, remaining: 5, capacity: 20 },
        ],
      },
    ];
  }
};

export const updateRemainingPlaces = async (serviceName, providerName, newRemaining) => {
  console.log(`Updating remaining places for ${serviceName} - ${providerName} to ${newRemaining}`);
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ success: true });
    }, 500);
  });
};

