    34→// Helper to get human-readable frequency
    35→const getHumanReadableFrequency = (ms) => {
    36→  if (ms <= 0) return 'Jamais'; // Handle 0 or negative frequency gracefully
    37→  if (ms >= FREQUENCY_MS.AN && ms % FREQUENCY_MS.AN === 0) {
    38→    return `${ms / FREQUENCY_MS.AN}/an`;
    39→  }
    40→  if (ms >= FREQUENCY_MS.MOIS && ms % FREQUENCY_MS.MOIS === 0) {
    41→    return `${ms / FREQUENCY_MS.MOIS}/mois`;
    42→  }
    43→  if (ms >= FREQUENCY_MS.SEMAINE && ms % FREQUENCY_MS.SEMAINE === 0) {
    44→    return `${ms / FREQUENCY_MS.SEMAINE}/semaine`;
    45→  }
    46→  if (ms >= FREQUENCY_MS.JOUR && ms % FREQUENCY_MS.JOUR === 0) {
    47→    return `${ms / FREQUENCY_MS.JOUR}/jour`;
    48→  }
    49→  if (ms >= FREQUENCY_MS.HEURE && ms % FREQUENCY_MS.HEURE === 0) {
    50→    return `${ms / FREQUENCY_MS.HEURE}/heure`;
    51→  }
    52→  if (ms >= FREQUENCY_MS.MINUTE && ms % FREQUENCY_MS.MINUTE === 0) {
    53→    return `${ms / FREQUENCY_MS.MINUTE}/min`;
    54→  }
    55→  return `${Math.round(ms / FREQUENCY_MS.SECONDE)} sec`; // Fallback to seconds
    56→};
    57→
    58→// Helper to format time remaining
    59→const formatTimeRemaining = (ms) => {
    60→  const seconds = Math.floor((ms / 1000) % 60);
    61→  const minutes = Math.floor((ms / (1000 * 60)) % 60);
    62→  const hours = Math.floor((ms / (1000 * 60 * 60)) % 24);
    63→  const days = Math.floor((ms / (1000 * 60 * 60 * 24)) % 30); // Approximate days in a month
    64→  const months = Math.floor(ms / (1000 * 60 * 60 * 24 * 30)); // Approximate months
    65→
    66→  let parts = [];
    67→  if (months > 0) parts.push(`${months} mois`);
    68→  if (days > 0) parts.push(`${days} jours`);
    69→  if (hours > 0) parts.push(`${hours} heures`);
    70→  if (minutes > 0) parts.push(`${minutes} minutes`);
    71→  if (seconds > 0) parts.push(`${seconds} secondes`);
