   489→  const getProcessedTasks = () => {
   490→    const allTasksFlat = [];
   491→    Object.entries(taskConfig).forEach(([categoryTitle, tasks]) => {
   492→      tasks.forEach(item => {
   493→        const lastEvent = lastEvents[item.id];
   494→        let isDone = false;
   495→        let nextDueDateMs;
   496→
   497→        // Ensure frequency is a valid positive number. Default to 1 day if 0 or invalid.
   498→        const effectiveFrequency = (item.frequency && item.frequency > 0) ? item.frequency : FREQUENCY_MS.JOUR;
   499→
   500→        if (lastEvent) {
   501→          const lastEventTimestamp = lastEvent.timestamp.toDate().getTime();
   502→          if (lastEvent.action === 'done') {
   503→            // Base the next due date on the last completion time.
   504→            nextDueDateMs = lastEventTimestamp + effectiveFrequency;
   505→          } else { // 'undone' or 'overdue'
   506→            // Task was explicitly marked as not clean, so it's due since that time.
   507→            nextDueDateMs = lastEventTimestamp;
   508→          }
   509→        } else {
   510→          // This is a new task with no history. Schedule its first cleaning from 'now'.
   511→          // The due date will move, but it avoids being stuck and prompts a first cleaning.
   512→          nextDueDateMs = now + effectiveFrequency;
   513→        }
   514→
   515→        // A task is only considered "done" if its last action was 'done'
   516→        // and we are still within the frequency period.
   517→        isDone = lastEvent?.action === 'done' && now < nextDueDateMs;
   518→        
   519→        // Final check to prevent NaN
   520→        if (isNaN(nextDueDateMs)) {
   521→            console.warn(`Invalid nextDueDateMs calculated for task ${item.name}. Defaulting to now.`);
   522→            nextDueDateMs = now;
   523→        }
   524→        
   525→        const nextDueDate = new Date(nextDueDateMs);
   526→        const timeRemainingMs = nextDueDateMs - now;
   527→
   528→        allTasksFlat.push({
   529→          ...item,
   530→          categoryTitle,
   531→          isDone,
   532→          lastEvent,
   533→          nextDueDate,
   534→          timeRemainingMs
   535→        });
   536→      });
   537→    });
   538→
   539→    let filtered = allTasksFlat;
   540→    if (showOnlyCritical) {
   541→      filtered = allTasksFlat.filter(t => t.timeRemainingMs <= 0 && !t.isDone);
   542→    }
   543→
   544→    const sorted = [...filtered].sort((a, b) => {
   545→      if (sortBy === 'name') {
   546→        return a.name.localeCompare(b.name);
   547→      } else if (sortBy === 'delay') {
   548→        return a.timeRemainingMs - b.timeRemainingMs;
   549→      } else {
   550→        const catCompare = a.categoryTitle.localeCompare(b.categoryTitle);
   551→        if (catCompare !== 0) return catCompare;
   552→        return a.name.localeCompare(b.name);
   553→      }
   554→    });
   555→
   556→    return sorted;
   557→  };
   558→
   559→  const processedTasks = getProcessedTasks();
